// 获取选中行的父行信息，用于判断部署和运行状态
// 入参：父实例仓库GUID
function getParentRowData(param) {
  let retObj = {};
  for (let i = 0; i < $Variable.tableData.length; i++) {
    let objItem = $Variable.tableData[i];
    if (param === objItem.purepoguid) {
      retObj = objItem;
      break;
    }
  }
  return retObj;
}

// 用于校验选中行的所有子行的部署状态
// 入参：选中行的子行数组
function verifyChildRowStatus(param) {
  for (let i = 0; i < param.length; i++) {
    let objItem = param[i];
    if ("未部署" !== objItem.deploy_state) {
      _Infor("请先撤销部署当前项的所有子节点！", "error");
      return -1;
    }
  }
  return 0;
}

// 消息提示窗
function _Infor(massage, type) {
  var options = {
    message: massage,
    type: type,
    duration: 3000,
    showClose: true
  };
  ShowMessage(options);
}

